 25→
 26→    const [title, setTitle] = useState(initialTitle || '')
 27→    const [wordCount, setWordCount] = useState(0);
 28→    const [editor] = useLexicalComposerContext();
 29→
 30→
 31→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 32→
 33→    const addUploadedImagePath = useCallback((imagePath) =>{
 34→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 35→    }, [])
 36→
 37→    useEffect(() => {
 38→        setTitle(initialTitle || '');
 39→    }, [initialTitle]);
 40→
 41→    const handleCloseEditor = useCallback(async() => {
 42→      if(uploadedImagePaths.length > 0){
 43→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
 44→        if(message){
 45→          // console.log(message.message)
 46→        }
 47→
 48→      }
 49→        editor.update(() => {
 50→            const state = editor.getEditorState().toJSON();
 51→            // console.log(state)
 52→
 53→            const root = $getRoot();
 54→            root.clear();
 55→            onClose();
 56→        })
 57→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 58→
 59→    const handleCloseEditorOnSave = useCallback(async() => {
 60→      editor.update(() => {
 61→            const state = editor.getEditorState().toJSON();
 62→            // console.log(state)
 63→
 64→            const root = $getRoot();
 65→            root.clear();
 66→            onClose();
 67→      })
 68→    }, [onClose, editor])
 69→
 70→    return(
 71→        <>
 72→        <div className='editor-parent-container'>
 73→
 74→            <motion.div
 75→            initial={{scale: 0, opacity: 0.8}}
 76→            animate={{scale: 1, opacity: 1}}
 77→            exit={{scale: 0.8, opacity: 0,}}
 78→            transition={{type: 'spring', stiffness: 260, damping: 25}}
 79→            className="editor-container"
 80→            >
 81→                <div className='editor-close-bttn-container'>
 82→                    <button
 83→                        onClick={() => handleCloseEditor()}
 84→                        className='editor-close-bttn'
 85→                        aria-label="Close editor"
 86→                        title="Close"
 87→                    >
 88→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
 89→                    </button>
 90→                </div>
 91→
 92→                <input value={title} onChange={(e) => setTitle(e.target.value)} className='content-title-input' type="text" placeholder='Title' />
