 99→                            onCloseOnSave={handleCloseEditorOnSave}
100→                            title={title}
101→                            setWordCount={setWordCount}
102→                            wordCount={wordCount}
103→                            promptId={promptId}
104→                        />
105→                    </ErrorBoundary>
106→                </div>
107→            </motion.div>
108→        </div>
109→        </>
110→    )
