 347→router.get('/getNotifications', requireAuth, async(req, res) =>{
 348→    const {before} = req.query;
 349→    const userId = req.userId;
 350→    const parsedLimit = parseLimitWithinRange(
 351→        req.query.limit,
 352→        NOTIFICATION_LIMIT_MIN,
 353→        NOTIFICATION_LIMIT_MAX,
 354→        NOTIFICATION_DEFAULT_LIMIT
 355→    );
 356→
 357→    if(parsedLimit == null){
 358→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 359→    }
 360→
 361→    // Fetch a generous amount from both tables, then merge and paginate
 362→    const fetchLimit = parsedLimit + 1;
 363→
 364→    let journalQuery = supabase
 365→    .from('notifications')
 366→    .select(NOTIFICATION_JOURNAL_SELECT)
 367→    .eq('receiver_id', userId)
 368→    .order('created_at', {ascending: false})
 369→    .order('id', {ascending: false})
 370→    .limit(fetchLimit)
 371→
 372→    let opinionQuery = supabase
 373→    .from('notification_opinions')
 374→    .select(NOTIFICATION_OPINION_SELECT)
 375→    .eq('receiver_id', userId)
 376→    .order('created_at', {ascending: false})
 377→    .order('id', {ascending: false})
 378→    .limit(fetchLimit)
 379→
 380→    if(before){
 381→        journalQuery = journalQuery.lt('created_at', before);
 382→        opinionQuery = opinionQuery.lt('created_at', before);
 383→    }
 384→
 385→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 386→
 387→    if(journalResult.error){
 388→        console.error('error while fetching data from notification table:', journalResult.error);
 389→        return res.status(500).json({error: 'error fetching data from notification table'});
 390→    }
 391→    if(opinionResult.error){
 392→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 393→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 394→    }
 395→
 396→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 397→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 398→
 399→    // Merge and sort by created_at descending
 400→    const merged = [...journalNotifs, ...opinionNotifs]
 401→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 402→
 403→    // Likes/bookmarks lookup only for journal notifications
 404→    const journalIds = [...new Set(
 405→        merged
 406→            .filter((n) => n.source === 'journal')
 407→            .map((n) => n.journal_id)
 408→            .filter(Boolean)
 409→    )];
 410→
 411→    let hasLikedResult = [];
 412→    let hasBookMarkedResult = [];
 413→    if(journalIds.length > 0){
 414→        const [hasLiked, hasBookMarked] = await Promise.all([
 415→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 416→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 417→        ]);
 418→
 419→        if(hasLiked.error || hasBookMarked.error){
 420→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 421→        }
 422→        hasLikedResult = hasLiked.data || [];
 423→        hasBookMarkedResult = hasBookMarked.data || [];
 424→    }
 425→
 426→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 427→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 428→
 429→    const formatted = merged.map((notif) => ({
 430→        ...notif,
 431→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 432→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 433→    }))
 434→
 435→    const hasMore = formatted.length > parsedLimit;
 436→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 437→
 438→    return res.status(200).json(
 439→        {
 440→            hasMore: hasMore,
 441→            data: slicedData,
 442→        }
 443→    )
 444→
 445→})
