 230→const extractFromLexical = (contentJson) => {
 231→    try {
 232→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 233→        const texts = [];
 234→        let firstImage = null;
 235→
 236→        const walk = (node) => {
 237→            if (!node || typeof node !== 'object') return;
 238→
 239→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 240→            if (nodeType === 'text' && typeof node.text === 'string') {
 241→                texts.push(node.text);
 242→            }
 243→
 244→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 245→            if (!firstImage && isImageNode) {
 246→                const image = imageFromNodeLike(node);
 247→                if (image) {
 248→                    firstImage = image;
 249→                }
 250→            }
 251→
 252→            if (Array.isArray(node.children)) {
 253→                node.children.forEach(walk);
 254→            }
 255→        };
 256→
 257→        if (parsed?.root) {
 258→            walk(parsed.root);
 259→        }
 260→
 261→        return {
 262→            text: normalizeWhitespace(texts.join(' ')),
 263→            image: firstImage
 264→        };
 265→    } catch {
 266→        return { text: '', image: null };
 267→    }
 268→};
