 323→const isPrivateIpv4Address = (ip) => {
 324→    const parts = ip.split('.').map((part) => Number(part));
 325→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 326→        return true;
 327→    }
 328→
 329→    const [a, b] = parts;
 330→    if (a === 10 || a === 127 || a === 0) return true;
 331→    if (a === 169 && b === 254) return true;
 332→    if (a === 172 && b >= 16 && b <= 31) return true;
 333→    if (a === 192 && b === 168) return true;
 334→    return false;
 335→};
