 347→const isPrivateIpAddress = (ip) => {
 348→    const ipVersion = net.isIP(ip);
 349→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 350→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 351→    return true;
 352→};
