 623→    await ensureShareFonts();
 624→
 625→    try {
 626→        const result = await getUserByUsernameService(username);
 627→        const user = result?.userData?.[0];
 628→        if (!user) {
 629→            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 630→        }
 631→
 632→        const displayName = normalizeWhitespace(user.name) || username;
 633→        const handle = `@${normalizeWhitespace(user.username || username)}`;
 634→        const bio = toPreviewText(user.bio || '', 120);
 635→
 636→        // ── Fetch background image ──
 637→        let bgBuffer = null;
 638→        const bgStyle = user.background || {};
 639→        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
 640→            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
 641→            : null;
 642→        const bgImageUrl = bgImageMatch?.[1];
 643→
 644→        if (bgImageUrl) {
 645→            const bgEval = evaluateShareImageCandidate(bgImageUrl);
 646→            if (bgEval.ok && bgEval.resolvedUrl) {
 647→                try {
 648→                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
 649→                    bgBuffer = remote.buffer;
 650→                } catch { /* use fallback gradient */ }
 651→            }
 652→        }
 653→
 654→        // ── Base layer: background or dark gradient ──
 655→        let baseLayer;
 656→        if (bgBuffer) {
 657→            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
 658→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
 659→                .toBuffer();
 660→        } else {
 661→            // Use profile's solid background color if available, otherwise dark fallback
 662→            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
 663→                ? bgStyle.background.trim()
 664→                : null;
 665→            const gradientSvg = solidColor
 666→                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 667→                    <rect width="100%" height="100%" fill="${solidColor}"/>
 668→                </svg>`
 669→                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 670→                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
 671→                        <stop offset="0%" stop-color="#1a1a2e"/>
 672→                        <stop offset="100%" stop-color="#16213e"/>
 673→                    </linearGradient></defs>
 674→                    <rect width="100%" height="100%" fill="url(#g)"/>
 675→                </svg>`;
 676→            baseLayer = await sharp(Buffer.from(gradientSvg))
 677→                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
 678→                .png()
 679→                .toBuffer();
 680→        }
 681→
 682→        // ── Dark overlay for text readability ──
 683→        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
 684→            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
 685→        </svg>`;
 686→        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();
 687→
 688→        // ── Circular avatar ──
 689→        let avatarComposite = null;
 690→        const avatarSize = 180;
 691→        const avatarUrl = user.image_url;
 692→        if (avatarUrl) {
 693→            const avatarEval = evaluateShareImageCandidate(avatarUrl);
 694→            if (avatarEval.ok && avatarEval.resolvedUrl) {
 695→                try {
 696→                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
 697→                    const circleMask = Buffer.from(
 698→                        `<svg width="${avatarSize}" height="${avatarSize}">
 699→                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
 700→                        </svg>`
 701→                    );
 702→                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
 703→                        .resize(avatarSize, avatarSize, { fit: 'cover' })
 704→                        .png()
 705→                        .toBuffer();
 706→                    const circularAvatar = await sharp(resizedAvatar)
 707→                        .composite([{ input: circleMask, blend: 'dest-in' }])
 708→                        .png()
 709→                        .toBuffer();
 710→                    avatarComposite = circularAvatar;
 711→                } catch { /* skip avatar */ }
 712→            }
