 969→const isMetricsAuthorized = (req) => {
 970→    if (!METRICS_TOKEN) {
 971→        return true;
 972→    }
 973→
 974→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
 975→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
 976→};
