 978→const buildMetricsPayload = () => {
 979→    const routeStats = Array.from(metricsState.routeStats.entries())
 980→        .map(([route, stat]) => ({
 981→            route,
 982→            count: stat.count,
 983→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
 984→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
 985→            bytesSent: stat.bytesSent,
 986→            statusBuckets: stat.statusBuckets,
 987→        }))
 988→        .sort((a, b) => b.count - a.count);
 989→
 990→    return {
 991→        startedAt: metricsState.startedAt,
 992→        requests: metricsState.requests,
 993→        responses: metricsState.responses,
 994→        inFlight: metricsState.inFlight,
 995→        bytesSent: metricsState.bytesSent,
 996→        statusBuckets: metricsState.statusBuckets,
 997→        routeStats: routeStats,
 998→    };
 999→};
