 23→export const uploadUserDataService = async(bio, name, image, userId, userEmail, username) =>{
 24→    if(!userId){
 25→        throw {status: 400, error: 'userId is undefined'};
 26→    }
 27→    if(!name || typeof name !== 'string' || name.length > 20){
 28→        throw {status: 400, error: 'name should be a string and not more than 20 characters'}
 29→    }
 30→    if(!bio || typeof bio !== 'string' || bio.length > 150){
 31→        throw {status: 400, error: 'bio should be a string and not more than 150 characters'}
 32→    }
 33→
 34→    // Validate username if provided
 35→    let validatedUsername = null;
 36→    if(username && typeof username === 'string'){
 37→        const trimmed = username.trim().toLowerCase();
 38→        if(trimmed.length < 3 || trimmed.length > 50){
 39→            throw {status: 400, error: 'username must be 3-50 characters'};
 40→        }
 41→        if(!/^[a-z0-9-]+$/.test(trimmed)){
 42→            throw {status: 400, error: 'username can only contain lowercase letters, numbers, and hyphens'};
 43→        }
 44→        // Check uniqueness
 45→        const {data: existing} = await supabase
 46→            .from('users')
 47→            .select('id')
 48→            .ilike('username', trimmed)
 49→            .limit(1);
 50→        if(existing && existing.length > 0){
 51→            throw {status: 409, error: 'username is already taken'};
 52→        }
 53→        validatedUsername = trimmed;
 54→    }
 55→
 56→    let publicUrl = null;
 57→    if(image){
 58→        const dataUrl = await imageUploader(image, userId, 'avatars');
 59→
 60→        publicUrl = dataUrl;
 61→    }
 62→
 63→    const data = {
 64→        bio: bio,
 65→        name: name,
 66→        id: userId,
 67→        user_email: userEmail || null,
 68→        image_url: publicUrl ? publicUrl : null
 69→    }
 70→
 71→    if(validatedUsername){
 72→        data.username = validatedUsername;
 73→    }
 74→
 75→    const {data: uploadData, error:errorUploadData} = await supabase
 76→    .from('users')
 77→    .insert([data])
 78→
 79→    if(errorUploadData){
 80→        console.error('supabase error:', errorUploadData.message);
 81→        throw {status:500, error:'supabase error while uploading data'}
 82→    }
 83→
 84→    return true;
 85→}
