// Line ~413 and ~588:
nodes: [HeadingNode, ImageNode, QuoteNode, MentionNode],
```

---

### 3. MentionPlugin (Autocomplete)

**File to create:** `C:\Users\johnm\iskrib_v3\client\src\components\HomePage\Editor\nodes\Plugins\MentionPlugin.jsx`

This follows the same plugin pattern as `ImagePlugin.jsx` at `C:\Users\johnm\iskrib_v3\client\src\components\HomePage\Editor\nodes\Plugins\ImagePlugin.jsx`, which uses `useLexicalComposerContext` and `editor.registerCommand`.

However, `MentionPlugin` is more complex because it needs to:
1. Listen for `@` character typed in the editor
2. Track the query string after `@`
3. Show a positioned dropdown
4. Handle keyboard navigation
5. Insert a `MentionNode` on selection

**Architecture approach -- TextNode transform + mutation listener:**

The most reliable approach for Lexical mention detection is to use a combination of:
- `editor.registerTextContentListener` or a `TEXT_NODE_TRANSFORM` to detect when `@` is typed
- `editor.registerUpdateListener` to track cursor position and extract the search query
- A React portal for the dropdown positioned near the cursor

**Detailed implementation:**

```javascript
import { useEffect, useState, useCallback, useRef } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import {
  $getSelection,
  $isRangeSelection,
  $isTextNode,
  KEY_ARROW_DOWN_COMMAND,
  KEY_ARROW_UP_COMMAND,
  KEY_ENTER_COMMAND,
  KEY_ESCAPE_COMMAND,
  KEY_TAB_COMMAND,
  COMMAND_PRIORITY_HIGH,
} from 'lexical';
import { $createMentionNode } from '../MentionNode';
import { useAuth } from '../../../../Context/useAuth';
import { searchFollowingUsers } from '../../../../../API/Api';

// Regex to detect @query pattern: match @ followed by optional chars (not spaces)
const MENTION_TRIGGER_REGEX = /@([\w-]*)$/;

export default function MentionPlugin() {
  const [editor] = useLexicalComposerContext();
  const { session } = useAuth();
  const [queryString, setQueryString] = useState(null);
  const [results, setResults] = useState([]);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [menuPosition, setMenuPosition] = useState(null);
  const debounceRef = useRef(null);

  // Listen for editor updates to detect @ trigger
  useEffect(() => {
    return editor.registerUpdateListener(({ editorState }) => {
      editorState.read(() => {
        const selection = $getSelection();
        if (!$isRangeSelection(selection) || !selection.isCollapsed()) {
          setQueryString(null);
          return;
        }

        const anchor = selection.anchor;
        if (anchor.type !== 'text') {
          setQueryString(null);
          return;
        }

        const anchorNode = anchor.getNode();
        const textBeforeCursor = anchorNode.getTextContent().slice(0, anchor.offset);
        const match = textBeforeCursor.match(MENTION_TRIGGER_REGEX);

        if (match) {
          setQueryString(match[1]); // The part after @

          // Calculate dropdown position from DOM selection
          const nativeSelection = window.getSelection();
          if (nativeSelection && nativeSelection.rangeCount > 0) {
            const range = nativeSelection.getRangeAt(0);
            const rect = range.getBoundingClientRect();
            setMenuPosition({
              top: rect.bottom + window.scrollY + 4,
              left: rect.left + window.scrollX,
            });
          }
        } else {
          setQueryString(null);
        }
      });
    });
  }, [editor]);

  // Fetch following users when query changes
  useEffect(() => {
    if (queryString === null) {
      setResults([]);
      setSelectedIndex(0);
      return;
    }

    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(async () => {
      if (!session?.access_token) return;
      try {
        const data = await searchFollowingUsers(session.access_token, queryString, 8);
        setResults(data?.data || []);
        setSelectedIndex(0);
      } catch (err) {
        console.error('mention search error:', err);
        setResults([]);
      }
    }, 200); // 200ms debounce

    return () => clearTimeout(debounceRef.current);
  }, [queryString, session?.access_token]);

  // Insert mention node
  const insertMention = useCallback((user) => {
    editor.update(() => {
      const selection = $getSelection();
      if (!$isRangeSelection(selection)) return;

      const anchor = selection.anchor;
      const anchorNode = anchor.getNode();
      if (!$isTextNode(anchorNode)) return;

      const textContent = anchorNode.getTextContent();
      const textBeforeCursor = textContent.slice(0, anchor.offset);
      const matchIndex = textBeforeCursor.lastIndexOf('@');

      if (matchIndex === -1) return;

      // Split the text node: keep text before @, replace @query with MentionNode
      const mentionNode = $createMentionNode(
        user.name,
        user.id,
        user.username
      );

      // Select the range from @ to cursor and replace it
      const beforeAtText = textContent.slice(0, matchIndex);
      const afterCursorText = textContent.slice(anchor.offset);

      anchorNode.setTextContent(beforeAtText);
      const afterNode = anchorNode.splitText(matchIndex);

      // If splitText returned nodes, insert mention after the first part
      anchorNode.setTextContent(beforeAtText);
      anchorNode.insertAfter(mentionNode);

      // Add a space after the mention for continued typing
      if (afterCursorText) {
        const textNode = $createTextNode(afterCursorText);
        mentionNode.insertAfter(textNode);
      } else {
        const spaceNode = $createTextNode(' ');
        mentionNode.insertAfter(spaceNode);
        spaceNode.select();
      }
    });

    setQueryString(null);
    setResults([]);
  }, [editor]);

  // Register keyboard commands when menu is open
  useEffect(() => {
    if (queryString === null || results.length === 0) return;

    const removeDown = editor.registerCommand(
      KEY_ARROW_DOWN_COMMAND,
      (e) => {
        e.preventDefault();
        setSelectedIndex((prev) => Math.min(prev + 1, results.length - 1));
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );

    const removeUp = editor.registerCommand(
      KEY_ARROW_UP_COMMAND,
      (e) => {
        e.preventDefault();
        setSelectedIndex((prev) => Math.max(prev - 1, 0));
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );

    const removeEnter = editor.registerCommand(
      KEY_ENTER_COMMAND,
      (e) => {
        if (results[selectedIndex]) {
          e.preventDefault();
          insertMention(results[selectedIndex]);
          return true;
        }
        return false;
      },
      COMMAND_PRIORITY_HIGH
    );

    const removeEscape = editor.registerCommand(
      KEY_ESCAPE_COMMAND,
      () => {
        setQueryString(null);
        return true;
      },
      COMMAND_PRIORITY_HIGH
    );

    const removeTab = editor.registerCommand(
      KEY_TAB_COMMAND,
      (e) => {
        if (results[selectedIndex]) {
          e.preventDefault();
          insertMention(results[selectedIndex]);
          return true;
        }
        return false;
      },
      COMMAND_PRIORITY_HIGH
    );

    return () => {
      removeDown();
      removeUp();
      removeEnter();
      removeEscape();
      removeTab();
    };
  }, [editor, queryString, results, selectedIndex, insertMention]);

  // Render dropdown
  if (queryString === null || results.length === 0 || !menuPosition) {
    return null;
  }

  return (
    <div
      className="mention-dropdown"
      style={{ top: menuPosition.top, left: menuPosition.left }}
    >
      {results.map((user, index) => (
        <div
          key={user.id}
          className={`mention-dropdown-item ${index === selectedIndex ? 'mention-dropdown-item--selected' : ''}`}
          onMouseDown={(e) => {
            e.preventDefault(); // Prevent editor blur
            insertMention(user);
          }}
          onMouseEnter={() => setSelectedIndex(index)}
        >
          <img
            src={user.image_url || '/assets/profile.jpg'}
            alt=""
            className="mention-dropdown-avatar"
          />
          <div className="mention-dropdown-info">
            <span className="mention-dropdown-name">{user.name}</span>
            <span className="mention-dropdown-username">@{user.username}</span>
          </div>
        </div>
      ))}
    </div>
  );
}
```

