### 4. Backend: Search Following Users Endpoint

**New service function** in `C:\Users\johnm\iskrib_v3\server\services\getService.js`:

```javascript
export const searchFollowingUsersService = async (userId, query, limit = 8) => {
    if (!userId) {
        throw { status: 401, error: 'authentication required' };
    }

    const parsedLimit = parseInt(limit);
    if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20) {
        throw { status: 400, error: 'limit should be between 1 and 20' };
    }

    // Step 1: Get IDs of users this person follows
    const { data: followData, error: followError } = await supabase
        .from('follows')
        .select('following_id')
        .eq('follower_id', userId);

    if (followError) {
        console.error('supabase error fetching follows:', followError.message);
        throw { status: 500, error: 'error fetching follows' };
    }

    if (!followData || followData.length === 0) {
        return { data: [] };
    }

    const followingIds = followData.map(f => f.following_id);

    // Step 2: If query is empty, return all followed users (up to limit)
    if (!query || !query.trim()) {
        const { data: users, error: usersError } = await supabase
            .from('users')
            .select('id, name, username, image_url, badge')
            .in('id', followingIds)
            .order('name')
            .limit(parsedLimit);

        if (usersError) {
            console.error('supabase error:', usersError.message);
            throw { status: 500, error: 'error fetching users' };
        }

        return { data: users || [] };
    }

    // Step 3: Search within followed users by name or username
    const escapedQuery = query.trim().replace(/[%_]/g, m => `\\${m}`);
    const selectColumns = 'id, name, username, image_url, badge';

    const [nameResult, usernameResult] = await Promise.all([
        supabase
            .from('users')
            .select(selectColumns)
            .in('id', followingIds)
            .ilike('name', `%${escapedQuery}%`)
            .limit(parsedLimit),
        supabase
            .from('users')
            .select(selectColumns)
            .in('id', followingIds)
            .ilike('username', `%${escapedQuery}%`)
            .limit(parsedLimit)
    ]);

    if (nameResult.error || usernameResult.error) {
        console.error('search error:', nameResult.error?.message || usernameResult.error?.message);
        throw { status: 500, error: 'error searching users' };
    }

    // Deduplicate
    const userMap = new Map();
    (nameResult.data || []).forEach(u => userMap.set(u.id, u));
    (usernameResult.data || []).forEach(u => {
        if (!userMap.has(u.id)) userMap.set(u.id, u);
    });

    const results = Array.from(userMap.values()).slice(0, parsedLimit);
    return { data: results };
};
```

