export function extractMentionUserIds(contentJson) {
    try {
        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
        const userIds = new Set();

        const walk = (node) => {
            if (!node || typeof node !== 'object') return;
            if (node.type === 'mention' && node.mentionUserId) {
                userIds.add(node.mentionUserId);
            }
            if (Array.isArray(node.children)) {
                node.children.forEach(walk);
            }
        };

        if (parsed?.root) {
            walk(parsed.root);
        }

        return Array.from(userIds);
    } catch {
        return [];
    }
}
```

**New utility: `createMentionNotifications`** -- add to `C:\Users\johnm\iskrib_v3\server\services\mentionService.js`:

```javascript
import supabase from "./supabase.js";

export async function createMentionNotifications(senderId, mentionedUserIds, journalId) {
    if (!mentionedUserIds || mentionedUserIds.length === 0) return;

    // Filter out self-mentions
    const recipientIds = mentionedUserIds.filter(id => id !== senderId);
    if (recipientIds.length === 0) return;

    // Batch insert notifications (max 50 mentions per post as safety)
    const notifications = recipientIds.slice(0, 50).map(receiverId => ({
        sender_id: senderId,
        receiver_id: receiverId,
        journal_id: journalId,
        type: 'mention',
        read: false,
    }));

    const { error } = await supabase
        .from('notifications')
        .insert(notifications);

    if (error) {
        console.error('error inserting mention notifications:', error.message);
    }
}
```

The notification type `'mention'` follows the existing pattern in the `notifications` table which already has a `type` column used for `'like'`, `'comment'`, `'reply'`, `'repost'`, and `'follow'`.

**Also apply to `updateJournalService`:** When a post is edited, re-extract mentions and insert notifications for any NEW mentions (users who weren't mentioned before). This requires comparing old and new mention sets.

